// Migrate V1 config to V2
export function migrateConfigV1ToV2(v1Config: StorefrontConfig, shopName: string): StorefrontConfigV2 {
  return {
    id: v1Config.id,
    shopId: v1Config.shopId,
    version: 2,
    published: v1Config.published,
    publishedAt: v1Config.publishedAt,
    theme: v1Config.theme,
    header: v1Config.header,
    footer: v1Config.footer,
    globalSeo: v1Config.seo,
    seo: v1Config.seo,
    pages: {
      // Migrate existing sections to landing page
      landing: {
        enabled: true,
        slug: '/',
        title: 'Home',
        sections: v1Config.sections as any[],
        seo: v1Config.seo,
        layout: 'default',
      },
      // Use defaults for other pages
      collection: { ...DEFAULT_COLLECTION_PAGE, sections: DEFAULT_COLLECTION_PAGE.sections.map(s => ({ ...s })) },
      product: { ...DEFAULT_PRODUCT_PAGE, sections: DEFAULT_PRODUCT_PAGE.sections.map(s => ({ ...s })) },
      cart: { ...DEFAULT_CART_PAGE, sections: DEFAULT_CART_PAGE.sections.map(s => ({ ...s })) },
      checkout: { ...DEFAULT_CHECKOUT_PAGE, sections: DEFAULT_CHECKOUT_PAGE.sections.map(s => ({ ...s })) },
      wishlist: { ...DEFAULT_WISHLIST_PAGE, sections: DEFAULT_WISHLIST_PAGE.sections.map(s => ({ ...s })) },
      profile: { ...DEFAULT_PROFILE_PAGE, sections: DEFAULT_PROFILE_PAGE.sections.map(s => ({ ...s })) },
      trackOrder: { ...DEFAULT_TRACK_ORDER_PAGE, sections: DEFAULT_TRACK_ORDER_PAGE.sections.map(s => ({ ...s })) },
      about: { ...DEFAULT_ABOUT_PAGE, sections: DEFAULT_ABOUT_PAGE.sections.map(s => ({ ...s })) },
      contact: { ...DEFAULT_CONTACT_PAGE, sections: DEFAULT_CONTACT_PAGE.sections.map(s => ({ ...s })) },
    },
    customCss: v1Config.customCss,
    customJs: v1Config.customJs,
    createdAt: v1Config.createdAt,
    updatedAt: new Date().toISOString(),
    // Keep for backward compatibility
    sections: v1Config.sections,
  };
}
